#include <stdio.h>
#include <math.h>

typedef struct {
    double (*getArea)(void*);
    double (*getPerimeter)(void*);
} Shape;

typedef struct {
    Shape shape;
    double length;
    double width;
} Rectangle;

typedef struct {
    Shape shape;
    double radius;
} Circle;

double rectangleGetArea(void* self) {
    Rectangle* rect = (Rectangle*)self;
    return rect->length * rect->width;
}

double rectangleGetPerimeter(void* self) {
    Rectangle* rect = (Rectangle*)self;
    return 2.0 * (rect->length + rect->width);
}

double circleGetArea(void* self) {
    Circle* circ = (Circle*)self;
    return M_PI * circ->radius * circ->radius;
}

double circleGetPerimeter(void* self) {
    Circle* circ = (Circle*)self;
    return 2.0 * M_PI * circ->radius;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int tc = 0; tc < T; ++tc) {
        int N;
        scanf("%d", &N);
        for (int i = 0; i < N; ++i) {
            char type[10];
            scanf("%s", type);
            if (strcmp(type, "Rectangle") == 0) {
                double length, width;
                scanf("%lf %lf", &length, &width);
                Rectangle rect;
                rect.shape.getArea = rectangleGetArea;
                rect.shape.getPerimeter = rectangleGetPerimeter;
                rect.length = length;
                rect.width = width;
                printf("Area: %.2f, Perimeter: %.2f\n", rect.shape.getArea(&rect), rect.shape.getPerimeter(&rect));
            } else if (strcmp(type, "Circle") == 0) {
                double radius;
                scanf("%lf", &radius);
                Circle circ;
                circ.shape.getArea = circleGetArea;
                circ.shape.getPerimeter = circleGetPerimeter;
                circ.radius = radius;
                printf("Area: %.2f, Perimeter: %.2f\n", circ.shape.getArea(&circ), circ.shape.getPerimeter(&circ));
            }
        }
    }
    return 0;
}

