#include <bits/stdc++.h>
using namespace std;

class Shape {
public:
    virtual double getArea() const = 0;
    virtual double getPerimeter() const = 0;
    virtual ~Shape() = default;
};

class Rectangle : public Shape {
    double length, width;
public:
    Rectangle(double l, double w) : length(l), width(w) {}
    double getArea() const override { return length * width; }
    double getPerimeter() const override { return 2.0 * (length + width); }
};

class Circle : public Shape {
    double radius;
public:
    Circle(double r) : radius(r) {}
    double getArea() const override { return M_PI * radius * radius; }
    double getPerimeter() const override { return 2.0 * M_PI * radius; }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        for (int i = 0; i < N; ++i) {
            string type; cin >> type;
            if (type == "Rectangle") {
                double l, w; cin >> l >> w;
                Rectangle rect(l, w);
                cout << fixed << setprecision(2);
                cout << "Area: " << rect.getArea() << ", Perimeter: " << rect.getPerimeter() << '\n';
            } else if (type == "Circle") {
                double r; cin >> r;
                Circle circ(r);
                cout << fixed << setprecision(2);
                cout << "Area: " << circ.getArea() << ", Perimeter: " << circ.getPerimeter() << '\n';
            }
        }
    }
    return 0;
}

