import java.io.*;
import java.util.*;

abstract class Shape {
    abstract double getArea();
    abstract double getPerimeter();
}

class Rectangle extends Shape {
    private final double length;
    private final double width;
    Rectangle(double length, double width) {
        this.length = length;
        this.width = width;
    }
    double getArea() { return length * width; }
    double getPerimeter() { return 2.0 * (length + width); }
}

class Circle extends Shape {
    private final double radius;
    Circle(double radius) { this.radius = radius; }
    double getArea() { return Math.PI * radius * radius; }
    double getPerimeter() { return 2.0 * Math.PI * radius; }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            for (int i = 0; i < N; ++i) {
                st = new StringTokenizer(br.readLine());
                String type = st.nextToken();
                if (type.equals("Rectangle")) {
                    double l = Double.parseDouble(st.nextToken());
                    double w = Double.parseDouble(st.nextToken());
                    Rectangle rect = new Rectangle(l, w);
                    sb.append(String.format(Locale.US, "Area: %.2f, Perimeter: %.2f\n", rect.getArea(), rect.getPerimeter()));
                } else if (type.equals("Circle")) {
                    double r = Double.parseDouble(st.nextToken());
                    Circle circ = new Circle(r);
                    sb.append(String.format(Locale.US, "Area: %.2f, Perimeter: %.2f\n", circ.getArea(), circ.getPerimeter()));
                }
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys
import math

class Shape:
    def getArea(self):
        pass
    def getPerimeter(self):
        pass

class Rectangle(Shape):
    def __init__(self, length, width):
        self.length = length
        self.width = width
    def getArea(self):
        return self.length * self.width
    def getPerimeter(self):
        return 2.0 * (self.length + self.width)

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius
    def getArea(self):
        return math.pi * self.radius * self.radius
    def getPerimeter(self):
        return 2.0 * math.pi * self.radius

data = sys.stdin.read().strip().splitlines()
idx = 0
def nextLine():
    global idx
    line = data[idx]
    idx += 1
    return line

def main():
    global idx
    T = int(nextLine())
    out_lines = []
    for _ in range(T):
        N = int(nextLine())
        for _ in range(N):
            parts = nextLine().split()
            if parts[0] == 'Rectangle':
                length = float(parts[1])
                width = float(parts[2])
                rect = Rectangle(length, width)
                out_lines.append(f"Area: {rect.getArea():.2f}, Perimeter: {rect.getPerimeter():.2f}")
            elif parts[0] == 'Circle':
                radius = float(parts[1])
                circ = Circle(radius)
                out_lines.append(f"Area: {circ.getArea():.2f}, Perimeter: {circ.getPerimeter():.2f}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

